INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('5f403a8c-b6e7-424c-8387-8a5ca6ee91c6-ex1', '5f403a8c-b6e7-424c-8387-8a5ca6ee91c6', 'racial', 'The school promotes racial harmony.', '这所学校倡导种族和谐。'),
  ('5f403a8c-b6e7-424c-8387-8a5ca6ee91c6-ex2', '5f403a8c-b6e7-424c-8387-8a5ca6ee91c6', 'racial', 'The commission documented persistent racial disparities in mortgage approval rates.', '委员会记录了房贷审批率中长期存在的种族差异。'),
  ('e1aee2af-d0e3-46a0-8a94-b30be38a861b-ex1', 'e1aee2af-d0e3-46a0-8a94-b30be38a861b', 'phase', 'The first phase of the project is done.', '项目第一阶段已完成。'),
  ('e1aee2af-d0e3-46a0-8a94-b30be38a861b-ex2', 'e1aee2af-d0e3-46a0-8a94-b30be38a861b', 'phase', 'The transition will phase out legacy exemptions over a five-year horizon.', '过渡安排将在五年内逐步取消既有豁免。'),
  ('81fbf6d3-6fea-435c-b227-d06f158467b5-ex1', '81fbf6d3-6fea-435c-b227-d06f158467b5', 'joke', 'He told a joke that made everyone laugh.', '他讲了一个让大家都笑了的笑话。'),
  ('81fbf6d3-6fea-435c-b227-d06f158467b5-ex2', '81fbf6d3-6fea-435c-b227-d06f158467b5', 'joke', 'Critics derided the voluntary code as a joke devoid of enforcement teeth.', '批评者讥讽这套自律准则毫无执行力，形同笑话。'),
  ('d1bf8f6a-6658-4662-ad8e-4afc36a47415-ex1', 'd1bf8f6a-6658-4662-ad8e-4afc36a47415', 'coat', 'Put on your coat; it is cold outside.', '穿上外套，外面冷。'),
  ('d1bf8f6a-6658-4662-ad8e-4afc36a47415-ex2', 'd1bf8f6a-6658-4662-ad8e-4afc36a47415', 'coat', 'A fresh coat of rhetoric could not conceal the proposal''s structural deficiencies.', '再华丽的言辞包装也掩盖不了该提案的结构性缺陷。'),
  ('8b553e06-f102-4b8a-b1fc-063b2f3a4c2e-ex1', '8b553e06-f102-4b8a-b1fc-063b2f3a4c2e', 'Mexican', 'We had Mexican food for dinner.', '我们晚饭吃了墨西哥菜。'),
  ('8b553e06-f102-4b8a-b1fc-063b2f3a4c2e-ex2', '8b553e06-f102-4b8a-b1fc-063b2f3a4c2e', 'Mexican', 'Mexican negotiators secured safeguards for seasonal agricultural exports.', '墨西哥谈判代表为季节性农产品出口争取到了保障条款。'),
  ('a89f548a-6c3d-4124-86bf-448512c91460-ex1', 'a89f548a-6c3d-4124-86bf-448512c91460', 'symptom', 'Fever is a common symptom of flu.', '发烧是流感的常见症状。'),
  ('a89f548a-6c3d-4124-86bf-448512c91460-ex2', 'a89f548a-6c3d-4124-86bf-448512c91460', 'symptom', 'The liquidity squeeze was a symptom of deeper solvency deterioration.', '流动性紧张是偿付能力深层恶化的一个征兆。'),
  ('70ef8a53-4bc3-43c6-b7bc-b99877346e30-ex1', '70ef8a53-4bc3-43c6-b7bc-b99877346e30', 'manufacturer', 'The manufacturer offers a two-year warranty.', '制造商提供两年保修。'),
  ('70ef8a53-4bc3-43c6-b7bc-b99877346e30-ex2', '70ef8a53-4bc3-43c6-b7bc-b99877346e30', 'manufacturer', 'The manufacturer bears strict liability for defects present at distribution.', '制造商对出厂时即存在的缺陷承担严格责任。'),
  ('cc0a38f1-6445-4af3-bbaf-30811dd1e96d-ex1', 'cc0a38f1-6445-4af3-bbaf-30811dd1e96d', 'philosophy', 'My philosophy is to always be honest.', '我的人生信条是永远诚实。'),
  ('cc0a38f1-6445-4af3-bbaf-30811dd1e96d-ex2', 'cc0a38f1-6445-4af3-bbaf-30811dd1e96d', 'philosophy', 'The ruling reflects a judicial philosophy of deference to agency expertise.', '该裁决体现了尊重行政机构专业判断的司法理念。'),
  ('74e92b48-c7b6-4f41-bfb7-db3ef928a451-ex1', '74e92b48-c7b6-4f41-bfb7-db3ef928a451', 'potato', 'We grow potatoes in our garden.', '我们在菜园里种土豆。'),
  ('74e92b48-c7b6-4f41-bfb7-db3ef928a451-ex2', '74e92b48-c7b6-4f41-bfb7-db3ef928a451', 'potato', 'The blight devastated potato harvests across the entire growing region.', '枯萎病重创了整个种植区的马铃薯收成。'),
  ('98722e85-50fd-4ad5-8cf9-799f79528d4f-ex1', '98722e85-50fd-4ad5-8cf9-799f79528d4f', 'foundation', 'The house has a strong foundation.', '这栋房子地基牢固。'),
  ('98722e85-50fd-4ad5-8cf9-799f79528d4f-ex2', '98722e85-50fd-4ad5-8cf9-799f79528d4f', 'foundation', 'The endowed foundation funds research immune from political interference.', '这家受捐赠基金会资助不受政治干预的研究。'),
  ('a398f543-e72c-474a-a92d-32b0428fd245-ex1', 'a398f543-e72c-474a-a92d-32b0428fd245', 'quote', 'Can you give me a quote for the repair?', '你能给我一个维修报价吗？'),
  ('a398f543-e72c-474a-a92d-32b0428fd245-ex2', 'a398f543-e72c-474a-a92d-32b0428fd245', 'quote', 'The judgment quotes extensively from the contemporaneous internal correspondence.', '判决书大量引用了当时的内部往来函件。'),
  ('7bfef3f8-f14f-40a8-9576-065c8cd85b9d-ex1', '7bfef3f8-f14f-40a8-9576-065c8cd85b9d', 'online', 'I bought these shoes online.', '这双鞋是我在网上买的。'),
  ('7bfef3f8-f14f-40a8-9576-065c8cd85b9d-ex2', '7bfef3f8-f14f-40a8-9576-065c8cd85b9d', 'online', 'The directive subjects online marketplaces to enhanced due diligence duties.', '该指令对网络交易平台施加了强化的尽职调查义务。'),
  ('b9eba344-7855-4b2b-ae6f-81543f1c5362-ex1', 'b9eba344-7855-4b2b-ae6f-81543f1c5362', 'negotiation', 'The price is open to negotiation.', '价格可以商量。'),
  ('b9eba344-7855-4b2b-ae6f-81543f1c5362-ex2', 'b9eba344-7855-4b2b-ae6f-81543f1c5362', 'negotiation', 'The negotiation collapsed over verification of the proposed dismantlement.', '谈判因拟议拆除工作的核查问题而破裂。'),
  ('959512ad-aa20-4634-ab52-87239ae80f91-ex1', '959512ad-aa20-4634-ab52-87239ae80f91', 'urge', 'I urge you to think it over.', '我劝你好好考虑一下。'),
  ('959512ad-aa20-4634-ab52-87239ae80f91-ex2', '959512ad-aa20-4634-ab52-87239ae80f91', 'urge', 'The rapporteur urged immediate ratification of the outstanding protocols.', '报告员敦促立即批准尚未生效的议定书。'),
  ('2f76aa52-60c3-4a7a-8ca6-6089a4b8b80e-ex1', '2f76aa52-60c3-4a7a-8ca6-6089a4b8b80e', 'occasion', 'We save this dish for special occasions.', '这道菜我们留到特殊场合才做。'),
  ('2f76aa52-60c3-4a7a-8ca6-6089a4b8b80e-ex2', '2f76aa52-60c3-4a7a-8ca6-6089a4b8b80e', 'occasion', 'On each occasion the warnings were acknowledged yet never escalated.', '每一次警告都被签收确认，却从未上报。'),
  ('46bf062e-b917-4dff-97b9-f22babf8099b-ex1', '46bf062e-b917-4dff-97b9-f22babf8099b', 'dust', 'The shelf is covered with dust.', '架子上落满了灰尘。'),
  ('46bf062e-b917-4dff-97b9-f22babf8099b-ex2', '46bf062e-b917-4dff-97b9-f22babf8099b', 'dust', 'Once the litigation dust settled, the doctrine had been fundamentally reshaped.', '诉讼尘埃落定之时，该法律原则已被根本重塑。'),
  ('4e268b2c-6a0c-4710-a655-d6f9aa4dddb8-ex1', '4e268b2c-6a0c-4710-a655-d6f9aa4dddb8', 'breathe', 'Breathe deeply and stay calm.', '深呼吸，保持冷静。'),
  ('4e268b2c-6a0c-4710-a655-d6f9aa4dddb8-ex2', '4e268b2c-6a0c-4710-a655-d6f9aa4dddb8', 'breathe', 'The amnesty allowed the program breathing room to demonstrate early results.', '特赦安排给该项目留出了展示初步成效的喘息空间。'),
  ('5894b312-4a97-4a4d-811c-a2cd86b051ae-ex1', '5894b312-4a97-4a4d-811c-a2cd86b051ae', 'elect', 'The class will elect a new monitor.', '班里要选一名新班长。'),
  ('5894b312-4a97-4a4d-811c-a2cd86b051ae-ex2', '5894b312-4a97-4a4d-811c-a2cd86b051ae', 'elect', 'Shareholders elect directors annually under the amended governance charter.', '根据修订后的治理章程，股东每年选举董事。'),
  ('a6cd1382-377c-4096-816f-cdcdbfc1e414-ex1', 'a6cd1382-377c-4096-816f-cdcdbfc1e414', 'investigator', 'The investigator examined the scene.', '调查员检查了现场。'),
  ('a6cd1382-377c-4096-816f-cdcdbfc1e414-ex2', 'a6cd1382-377c-4096-816f-cdcdbfc1e414', 'investigator', 'The lead investigator was granted access to privileged correspondence by court order.', '经法院令准许，首席调查员获准查阅特权通信。'),
  ('8b11bc84-7bc6-4e7a-a479-6079fea18a3b-ex1', '8b11bc84-7bc6-4e7a-a479-6079fea18a3b', 'jacket', 'Take a jacket; it might rain.', '带件夹克，可能要下雨。'),
  ('8b11bc84-7bc6-4e7a-a479-6079fea18a3b-ex2', '8b11bc84-7bc6-4e7a-a479-6079fea18a3b', 'jacket', 'The counterfeit jackets bore trademarks registered to the complainant.', '这些假冒夹克印有投诉方注册的商标。'),
  ('5ef81760-0c68-4256-af54-10a42a0ad98b-ex1', '5ef81760-0c68-4256-af54-10a42a0ad98b', 'glad', 'I am glad you could come.', '很高兴你能来。'),
  ('5ef81760-0c68-4256-af54-10a42a0ad98b-ex2', '5ef81760-0c68-4256-af54-10a42a0ad98b', 'glad', 'The secretariat was glad to report full compliance across member states.', '秘书处欣然报告各成员国已全面履约。'),
  ('d880f030-2fff-424e-a124-e67768626966-ex1', 'd880f030-2fff-424e-a124-e67768626966', 'ordinary', 'It was just an ordinary Tuesday.', '那只是一个平常的星期二。'),
  ('d880f030-2fff-424e-a124-e67768626966-ex2', 'd880f030-2fff-424e-a124-e67768626966', 'ordinary', 'The disclosure must be intelligible to the ordinary prudent investor.', '披露内容必须让普通审慎投资者能够理解。'),
  ('5aad6d94-64da-471c-8e81-7e1f40b00b76-ex1', '5aad6d94-64da-471c-8e81-7e1f40b00b76', 'reduction', 'The store offers a price reduction this week.', '这家店本周降价促销。'),
  ('5aad6d94-64da-471c-8e81-7e1f40b00b76-ex2', '5aad6d94-64da-471c-8e81-7e1f40b00b76', 'reduction', 'The verified emission reductions qualify for credit under the trading scheme.', '经核证的减排量可在交易机制下获得配额抵免。'),
  ('73d9c8a9-05bd-44f0-9ba1-b33366fabb53-ex1', '73d9c8a9-05bd-44f0-9ba1-b33366fabb53', 'rarely', 'He rarely arrives late.', '他很少迟到。'),
  ('73d9c8a9-05bd-44f0-9ba1-b33366fabb53-ex2', '73d9c8a9-05bd-44f0-9ba1-b33366fabb53', 'rarely', 'Sanctions of this severity are rarely imposed absent aggravating conduct.', '如无加重情节，如此严厉的处罚极少施加。'),
  ('020f66b4-7bb2-4978-946a-10f2c7a8a81c-ex1', '020f66b4-7bb2-4978-946a-10f2c7a8a81c', 'pack', 'Pack your bags; we leave at dawn.', '收拾行李，我们天亮出发。'),
  ('020f66b4-7bb2-4978-946a-10f2c7a8a81c-ex2', '020f66b4-7bb2-4978-946a-10f2c7a8a81c', 'pack', 'The omnibus bill packs unrelated provisions into a single unamendable text.', '这项综合法案把互不相关的条款塞进一个不可修改的文本。'),
  ('069801c5-b71e-40e9-927b-65852548c45e-ex1', '069801c5-b71e-40e9-927b-65852548c45e', 'suicide', 'The hotline helps prevent suicide.', '这条热线帮助预防自杀。'),
  ('069801c5-b71e-40e9-927b-65852548c45e-ex2', '069801c5-b71e-40e9-927b-65852548c45e', 'suicide', 'The strategy embeds suicide prevention within primary healthcare delivery.', '该战略将自杀预防纳入初级医疗服务体系。'),
  ('b03b961a-420c-41c4-93b5-3ea74e360807-ex1', 'b03b961a-420c-41c4-93b5-3ea74e360807', 'numerous', 'She has numerous friends at school.', '她在学校有很多朋友。'),
  ('b03b961a-420c-41c4-93b5-3ea74e360807-ex2', 'b03b961a-420c-41c4-93b5-3ea74e360807', 'numerous', 'Numerous precedents support the narrower construction the respondent advances.', '大量先例支持被告所主张的较窄解释。'),
  ('d5ade654-c151-4ff9-8f5f-5b14f79aeaaf-ex1', 'd5ade654-c151-4ff9-8f5f-5b14f79aeaaf', 'substance', 'The bottle contains an unknown substance.', '瓶子里装着不明物质。'),
  ('d5ade654-c151-4ff9-8f5f-5b14f79aeaaf-ex2', 'd5ade654-c151-4ff9-8f5f-5b14f79aeaaf', 'substance', 'Courts examine the substance of the arrangement rather than its formal label.', '法院审查安排的实质，而非其形式上的名称。'),
  ('cd0d727b-60fc-46e6-8449-e448ddfbe9b1-ex1', 'cd0d727b-60fc-46e6-8449-e448ddfbe9b1', 'discipline', 'Learning piano takes discipline.', '学钢琴需要自律。'),
  ('cd0d727b-60fc-46e6-8449-e448ddfbe9b1-ex2', 'cd0d727b-60fc-46e6-8449-e448ddfbe9b1', 'discipline', 'The tribunal imposed professional discipline for breach of fiduciary standards.', '法庭因违反信义标准实施了职业惩戒。'),
  ('a20e879b-add6-4981-97cc-d0486a355149-ex1', 'a20e879b-add6-4981-97cc-d0486a355149', 'elsewhere', 'The cafe was full, so we went elsewhere.', '咖啡馆满了，我们就去了别处。'),
  ('a20e879b-add6-4981-97cc-d0486a355149-ex2', 'a20e879b-add6-4981-97cc-d0486a355149', 'elsewhere', 'Capital migrated elsewhere as the regulatory burden grew disproportionate.', '随着监管负担过重，资本流向了其他地方。'),
  ('e33bd4a8-21cc-4fe5-a887-3908b1991b8f-ex1', 'e33bd4a8-21cc-4fe5-a887-3908b1991b8f', 'iron', 'I need to iron my shirt.', '我需要熨衬衫。'),
  ('e33bd4a8-21cc-4fe5-a887-3908b1991b8f-ex2', 'e33bd4a8-21cc-4fe5-a887-3908b1991b8f', 'iron', 'The accord dismantled tariffs that had protected the iron industry for decades.', '该协定取消了数十年来保护钢铁工业的关税。'),
  ('123f37e3-b72a-4f2a-bdac-5f6cd3ecaee9-ex1', '123f37e3-b72a-4f2a-bdac-5f6cd3ecaee9', 'practical', 'She gave me practical advice.', '她给了我很实用的建议。'),
  ('123f37e3-b72a-4f2a-bdac-5f6cd3ecaee9-ex2', '123f37e3-b72a-4f2a-bdac-5f6cd3ecaee9', 'practical', 'The ruling has practical consequences extending far beyond the named parties.', '该裁决的实际影响远超案件当事人本身。'),
  ('2fa9e0e4-b84d-4b53-b146-1855b467dae7-ex1', '2fa9e0e4-b84d-4b53-b146-1855b467dae7', 'moreover', 'The dish is cheap; moreover, it is delicious.', '这道菜便宜，而且好吃。'),
  ('2fa9e0e4-b84d-4b53-b146-1855b467dae7-ex2', '2fa9e0e4-b84d-4b53-b146-1855b467dae7', 'moreover', 'Moreover, the contested clause conflicts with mandatory provisions of the statute.', '此外，争议条款还与法规的强制性规定相抵触。'),
  ('25c7fb50-8616-4d2d-8539-de2f5ff9aabf-ex1', '25c7fb50-8616-4d2d-8539-de2f5ff9aabf', 'passion', 'She has a passion for painting.', '她热爱绘画。'),
  ('25c7fb50-8616-4d2d-8539-de2f5ff9aabf-ex2', '25c7fb50-8616-4d2d-8539-de2f5ff9aabf', 'passion', 'Judicial reasoning demands analysis insulated from public passion.', '司法推理需要不受公众激情影响的分析。'),
  ('a24eeb49-77de-4d8b-bbe4-17b2ae698805-ex1', 'a24eeb49-77de-4d8b-bbe4-17b2ae698805', 'volunteer', 'She volunteers at the animal shelter.', '她在动物收容所做志愿者。'),
  ('a24eeb49-77de-4d8b-bbe4-17b2ae698805-ex2', 'a24eeb49-77de-4d8b-bbe4-17b2ae698805', 'volunteer', 'The statute shields volunteers from liability for good-faith assistance.', '该法规保护志愿者免于因善意施助而承担责任。'),
  ('6425944c-c2c5-4685-8ee8-69abeea7f092-ex1', '6425944c-c2c5-4685-8ee8-69abeea7f092', 'implement', 'We will implement the new plan next month.', '我们下个月实施新计划。'),
  ('6425944c-c2c5-4685-8ee8-69abeea7f092-ex2', '6425944c-c2c5-4685-8ee8-69abeea7f092', 'implement', 'Member states must implement the directive within the transposition period.', '成员国必须在转化期限内实施该指令。'),
  ('af14e59c-3a7d-47ab-ac24-96af27c93877-ex1', 'af14e59c-3a7d-47ab-ac24-96af27c93877', 'essentially', 'The two plans are essentially the same.', '这两个方案本质上是一样的。'),
  ('af14e59c-3a7d-47ab-ac24-96af27c93877-ex2', 'af14e59c-3a7d-47ab-ac24-96af27c93877', 'essentially', 'The arrangement is essentially a guarantee, whatever label the parties attached.', '无论双方如何命名，这一安排本质上就是担保。'),
  ('6c85a060-b8ab-452b-8843-0c942409ee84-ex1', '6c85a060-b8ab-452b-8843-0c942409ee84', 'gene', 'Scientists study how genes affect health.', '科学家研究基因如何影响健康。'),
  ('6c85a060-b8ab-452b-8843-0c942409ee84-ex2', '6c85a060-b8ab-452b-8843-0c942409ee84', 'gene', 'The patentability of isolated genes was definitively resolved by the high court.', '分离基因的可专利性问题由最高法院作出了最终裁决。'),
  ('09f1b3d3-743e-464b-98a0-4a79282ece21-ex1', '09f1b3d3-743e-464b-98a0-4a79282ece21', 'enforcement', 'Strict enforcement keeps the roads safe.', '严格执法保障道路安全。'),
  ('09f1b3d3-743e-464b-98a0-4a79282ece21-ex2', '09f1b3d3-743e-464b-98a0-4a79282ece21', 'enforcement', 'Cross-border enforcement of judgments depends on reciprocal recognition treaties.', '判决的跨境执行依赖于相互承认条约。'),
  ('b9e904ba-50d7-4aed-bdb1-d1fc6692221d-ex1', 'b9e904ba-50d7-4aed-bdb1-d1fc6692221d', 'sauce', 'The pasta needs more sauce.', '意面需要多加点酱。'),
  ('b9e904ba-50d7-4aed-bdb1-d1fc6692221d-ex2', 'b9e904ba-50d7-4aed-bdb1-d1fc6692221d', 'sauce', 'The trade dispute over the protected sauce designation reached the appellate panel.', '围绕该酱料原产地保护的贸易争端已提交上诉机构。'),
  ('2bfaa04a-8c03-4dac-b2e6-16cddb4524a5-ex1', '2bfaa04a-8c03-4dac-b2e6-16cddb4524a5', 'independence', 'The country gained independence in 1960.', '这个国家于1960年获得独立。'),
  ('2bfaa04a-8c03-4dac-b2e6-16cddb4524a5-ex2', '2bfaa04a-8c03-4dac-b2e6-16cddb4524a5', 'independence', 'Auditor independence is compromised where consulting fees dwarf audit fees.', '当咨询费远超审计费时，审计师的独立性便受到损害。'),
  ('5d23283b-f776-4117-aa14-971fa5908c6c-ex1', '5d23283b-f776-4117-aa14-971fa5908c6c', 'marketing', 'She works in the marketing department.', '她在市场部工作。'),
