  ('316611ef-884f-4790-8e74-7f3cf611725d-ex2', '316611ef-884f-4790-8e74-7f3cf611725d', 'criteria', 'The eligibility criteria were applied uniformly across all applicant classes.', '资格标准统一适用于所有申请人类别。'),
  ('31c241a7-4621-4eab-af99-4c392f2f24ee-ex1', '31c241a7-4621-4eab-af99-4c392f2f24ee', 'dealer', 'We bought the car from a local dealer.', '我们从当地经销商那里买了车。'),
  ('31c241a7-4621-4eab-af99-4c392f2f24ee-ex2', '31c241a7-4621-4eab-af99-4c392f2f24ee', 'dealer', 'Registered dealers bear reporting obligations for transactions above the threshold.', '注册交易商对超过门槛的交易负有申报义务。'),
  ('857c65aa-48c6-4626-af6c-cb96659dcc40-ex1', '857c65aa-48c6-4626-af6c-cb96659dcc40', 'via', 'We flew to London via Paris.', '我们经巴黎飞往伦敦。'),
  ('857c65aa-48c6-4626-af6c-cb96659dcc40-ex2', '857c65aa-48c6-4626-af6c-cb96659dcc40', 'via', 'The funds moved via correspondent accounts across three jurisdictions.', '这些资金经由三个司法管辖区的代理账户流转。'),
  ('40953cbd-b49f-41e8-983e-515b3381aa89-ex1', '40953cbd-b49f-41e8-983e-515b3381aa89', 'utility', 'The bill covers all utilities.', '账单包含所有水电煤气费。'),
  ('40953cbd-b49f-41e8-983e-515b3381aa89-ex2', '40953cbd-b49f-41e8-983e-515b3381aa89', 'utility', 'The utility''s rates are set through adversarial proceedings before the commission.', '该公用事业公司的费率通过委员会的对审程序确定。'),
  ('0832e57c-7d99-4a00-a9c4-8f37fa5cb5f6-ex1', '0832e57c-7d99-4a00-a9c4-8f37fa5cb5f6', 'precisely', 'The train left precisely on time.', '火车准点发车。'),
