  ('47a04df5-7484-45af-a240-5b587076d500-ex1', '47a04df5-7484-45af-a240-5b587076d500', 'highway', 'The highway is busy during holidays.', '假期里高速公路车流繁忙。'),
  ('47a04df5-7484-45af-a240-5b587076d500-ex2', '47a04df5-7484-45af-a240-5b587076d500', 'highway', 'The highway concession reverts to the state upon expiry of the term.', '高速公路特许经营权在期限届满后归还国家。'),
  ('899f62e7-c296-48c0-ab45-8d48736f5618-ex1', '899f62e7-c296-48c0-ab45-8d48736f5618', 'clinical', 'She has years of clinical experience.', '她有多年的临床经验。'),
  ('899f62e7-c296-48c0-ab45-8d48736f5618-ex2', '899f62e7-c296-48c0-ab45-8d48736f5618', 'clinical', 'Clinical trial data must be registered and published under the transparency rules.', '根据透明度规则，临床试验数据必须登记并公布。'),
  ('e51b1636-f049-4e5e-9e59-7444e8802c2a-ex1', 'e51b1636-f049-4e5e-9e59-7444e8802c2a', 'routine', 'Exercise is part of my daily routine.', '锻炼是我日常生活的一部分。'),
  ('e51b1636-f049-4e5e-9e59-7444e8802c2a-ex2', 'e51b1636-f049-4e5e-9e59-7444e8802c2a', 'routine', 'What began as routine inspection uncovered systematic record falsification.', '一次例行检查竟揭出了系统性的记录造假。'),
  ('4e41e03e-bae0-4199-87a6-c0f3b13a2eae-ex1', '4e41e03e-bae0-4199-87a6-c0f3b13a2eae', 'wage', 'The job pays a fair wage.', '这份工作工资公道。'),
  ('4e41e03e-bae0-4199-87a6-c0f3b13a2eae-ex2', '4e41e03e-bae0-4199-87a6-c0f3b13a2eae', 'wage', 'The wage floor adjusts annually under the statutory indexation mechanism.', '最低工资按法定指数化机制每年调整。'),
  ('ad0937da-0767-4b9d-b44c-80004621d25d-ex1', 'ad0937da-0767-4b9d-b44c-80004621d25d', 'normally', 'I normally walk to work.', '我通常走路上班。'),
  ('ad0937da-0767-4b9d-b44c-80004621d25d-ex2', 'ad0937da-0767-4b9d-b44c-80004621d25d', 'normally', 'Documents normally privileged may be disclosed under the crime-fraud exception.', '通常受特权保护的文件，在犯罪欺诈例外下可被披露。'),
  ('d40af116-5360-4020-8bcc-a94342354f99-ex1', 'd40af116-5360-4020-8bcc-a94342354f99', 'phrase', 'Repeat the phrase after me.', '跟我重复这个短语。'),
  ('d40af116-5360-4020-8bcc-a94342354f99-ex2', 'd40af116-5360-4020-8bcc-a94342354f99', 'phrase', 'The entire appeal turns on the construction of a single statutory phrase.', '整个上诉的成败系于一个法定措辞的解释。'),
  ('8203e6a7-2cde-476f-9e54-b98d9c352088-ex1', '8203e6a7-2cde-476f-9e54-b98d9c352088', 'ingredient', 'Flour is the main ingredient in bread.', '面粉是面包的主要原料。'),
