  ('8a1b0eae-2318-42c2-87af-5ab8a5fa041c-ex1', '8a1b0eae-2318-42c2-87af-5ab8a5fa041c', 'refugee', 'The family welcomed a refugee into their home.', '这家人收留了一名难民。'),
