  ('e4a54cf9-0802-42d1-96e8-5d82c40c5892-ex2', 'e4a54cf9-0802-42d1-96e8-5d82c40c5892', 'killer', 'The clause proved a deal-killer once its indemnity scope became apparent.', '赔偿范围一旦明朗，这一条款便成了交易的致命障碍。'),
  ('4385fff3-4459-4426-b79c-99188b18e762-ex1', '4385fff3-4459-4426-b79c-99188b18e762', 'assign', 'The teacher assigned us homework.', '老师给我们布置了作业。'),
