  ('c700e1ee-086e-4d73-a023-61b997b42e56-ex1', 'c700e1ee-086e-4d73-a023-61b997b42e56', 'chemical', 'Don''t mix these cleaning chemicals.', '不要混合这些清洁化学品。'),
