  ('f595d2e2-b1d9-409c-9c39-aecdea0f2d5e-ex2', 'f595d2e2-b1d9-409c-9c39-aecdea0f2d5e', 'mode', 'The parties selected arbitration as their exclusive mode of dispute resolution.', '双方选择仲裁作为其唯一的争端解决方式。'),
  ('f6d675a5-6e94-4925-96e9-90b92e74f37e-ex1', 'f6d675a5-6e94-4925-96e9-90b92e74f37e', 'dialogue', 'The two friends had a long dialogue.', '两个朋友长谈了一番。'),
  ('f6d675a5-6e94-4925-96e9-90b92e74f37e-ex2', 'f6d675a5-6e94-4925-96e9-90b92e74f37e', 'dialogue', 'Sustained dialogue is the only durable alternative to escalating confrontation.', '持续对话是避免对抗升级的唯一持久之选。'),
  ('fe01ad5a-96a2-4af9-b996-630b009a2597-ex1', 'fe01ad5a-96a2-4af9-b996-630b009a2597', 'imply', 'Are you implying that I am wrong?', '你是在暗示我错了吗？'),
