  ('fa0fe1c7-3bbb-4c33-a350-0a5285c7b6aa-ex2', 'fa0fe1c7-3bbb-4c33-a350-0a5285c7b6aa', 'dismiss', 'The court declined to dismiss the claims at the preliminary stage.', '法院拒绝在初步阶段驳回这些诉求。'),
  ('3f2b6fac-ee86-4ce5-9318-9c7c112191ab-ex1', '3f2b6fac-ee86-4ce5-9318-9c7c112191ab', 'aircraft', 'The aircraft landed safely.', '飞机安全着陆。'),
  ('3f2b6fac-ee86-4ce5-9318-9c7c112191ab-ex2', '3f2b6fac-ee86-4ce5-9318-9c7c112191ab', 'aircraft', 'The convention governs liability for damage caused by aircraft to third parties.', '该公约规范航空器对第三方造成损害的责任。'),
  ('04a96773-5b19-444c-b209-a609cdd56d24-ex1', '04a96773-5b19-444c-b209-a609cdd56d24', 'delivery', 'The delivery arrives tomorrow morning.', '快递明天上午到。'),
  ('04a96773-5b19-444c-b209-a609cdd56d24-ex2', '04a96773-5b19-444c-b209-a609cdd56d24', 'delivery', 'Delivery against payment minimizes settlement risk in cross-border transactions.', '款货两讫机制将跨境交易的结算风险降至最低。'),
  ('1c8978fc-dc4f-4310-9dfc-6a304e0f262a-ex1', '1c8978fc-dc4f-4310-9dfc-6a304e0f262a', 'mainly', 'The audience was mainly young people.', '观众主要是年轻人。'),
  ('1c8978fc-dc4f-4310-9dfc-6a304e0f262a-ex2', '1c8978fc-dc4f-4310-9dfc-6a304e0f262a', 'mainly', 'The losses stemmed mainly from concentrated and unhedged positions.', '这些损失主要源于集中且未对冲的头寸。'),
  ('d4d245c4-92ff-45f0-a37f-cc9b2acccc05-ex1', 'd4d245c4-92ff-45f0-a37f-cc9b2acccc05', 'bake', 'She likes to bake cookies on weekends.', '她喜欢周末烤饼干。'),
  ('d4d245c4-92ff-45f0-a37f-cc9b2acccc05-ex2', 'd4d245c4-92ff-45f0-a37f-cc9b2acccc05', 'bake', 'The risks were baked into the structure long before the collapse.', '早在崩盘之前，风险就已嵌入这一架构之中。'),
  ('96d2036e-6530-4c63-a780-1123e0299cfe-ex1', '96d2036e-6530-4c63-a780-1123e0299cfe', 'freeze', 'Water freezes at zero degrees.', '水在零度结冰。'),
  ('96d2036e-6530-4c63-a780-1123e0299cfe-ex2', '96d2036e-6530-4c63-a780-1123e0299cfe', 'freeze', 'The court ordered an asset freeze pending the outcome of the fraud claim.', '在欺诈索赔结果出炉之前，法院下令冻结资产。'),
