  ('b7730aa3-2f13-411f-9dc5-d9a4686f1bfb-ex1', 'b7730aa3-2f13-411f-9dc5-d9a4686f1bfb', 'tongue', 'She bit her tongue by accident.', '她不小心咬到了舌头。'),
