  ('6b7678ac-5ae8-4f02-a50c-0e63fa452dfa-ex1', '6b7678ac-5ae8-4f02-a50c-0e63fa452dfa', 'split', 'Let''s split the bill.', '我们平摊账单吧。'),
  ('6b7678ac-5ae8-4f02-a50c-0e63fa452dfa-ex2', '6b7678ac-5ae8-4f02-a50c-0e63fa452dfa', 'split', 'The appellate panel split sharply on the proper construction of the clause.', '上诉合议庭在该条款的正确解释上严重分歧。'),
  ('219b9aa2-c2a6-4f9f-85ce-d0caf16c2ae1-ex1', '219b9aa2-c2a6-4f9f-85ce-d0caf16c2ae1', 'violate', 'Don''t violate the traffic rules.', '不要违反交通规则。'),
  ('219b9aa2-c2a6-4f9f-85ce-d0caf16c2ae1-ex2', '219b9aa2-c2a6-4f9f-85ce-d0caf16c2ae1', 'violate', 'The measure was held to violate the equal protection guarantee.', '该措施被裁定违反平等保护保障。'),
  ('e4c4486a-f2bd-4dbf-af6e-d167387807e5-ex1', 'e4c4486a-f2bd-4dbf-af6e-d167387807e5', 'partnership', 'They formed a business partnership.', '他们建立了商业合伙关系。'),
  ('e4c4486a-f2bd-4dbf-af6e-d167387807e5-ex2', 'e4c4486a-f2bd-4dbf-af6e-d167387807e5', 'partnership', 'Each partner bears unlimited liability for the partnership''s obligations.', '每位合伙人对合伙企业的债务承担无限责任。'),
  ('86120d8e-9e65-4a4d-a6a1-1916d93aac8a-ex1', '86120d8e-9e65-4a4d-a6a1-1916d93aac8a', 'pollution', 'Air pollution is a serious problem.', '空气污染是个严重的问题。'),
  ('86120d8e-9e65-4a4d-a6a1-1916d93aac8a-ex2', '86120d8e-9e65-4a4d-a6a1-1916d93aac8a', 'pollution', 'The polluter bears strict liability for remediation of the contamination.', '污染者对污染治理承担严格责任。'),
  ('98ce675d-a042-4aba-bdb4-e53945e93827-ex1', '98ce675d-a042-4aba-bdb4-e53945e93827', 'emission', 'The factory reduced its emissions.', '这家工厂减少了排放。'),
  ('98ce675d-a042-4aba-bdb4-e53945e93827-ex2', '98ce675d-a042-4aba-bdb4-e53945e93827', 'emission', 'The accord obliges signatories to verify emissions through independent audit.', '该协定要求签署方通过独立审计核查排放量。'),
  ('f058efe3-eb4c-4a0b-bd5a-c20c51ef65cb-ex1', 'f058efe3-eb4c-4a0b-bd5a-c20c51ef65cb', 'steady', 'Keep the camera steady.', '保持相机稳定。'),
  ('f058efe3-eb4c-4a0b-bd5a-c20c51ef65cb-ex2', 'f058efe3-eb4c-4a0b-bd5a-c20c51ef65cb', 'steady', 'Steady erosion of supervisory independence preceded the eventual crisis.', '监管独立性的逐步削弱先于最终危机的爆发。'),
  ('1f40ce81-1bcc-4901-a9fd-972f9a68a514-ex1', '1f40ce81-1bcc-4901-a9fd-972f9a68a514', 'vital', 'Water is vital for life.', '水对生命至关重要。'),
  ('1f40ce81-1bcc-4901-a9fd-972f9a68a514-ex2', '1f40ce81-1bcc-4901-a9fd-972f9a68a514', 'vital', 'Judicial independence is vital to the legitimacy of constitutional review.', '司法独立对宪法审查的正当性至关重要。'),
  ('0d1e3cfd-fe31-4189-b523-ba3407766faf-ex1', '0d1e3cfd-fe31-4189-b523-ba3407766faf', 'fate', 'We don''t know the fate of the missing ship.', '我们不知道失踪船只的命运。'),
  ('0d1e3cfd-fe31-4189-b523-ba3407766faf-ex2', '0d1e3cfd-fe31-4189-b523-ba3407766faf', 'fate', 'The bill''s fate rested on a single undecided cross-bench vote.', '该法案的命运系于一张尚未表态的中立议员选票。'),
  ('5caa701d-0d82-43dd-b4db-79a4b68dd5b6-ex1', '5caa701d-0d82-43dd-b4db-79a4b68dd5b6', 'earnings', 'Her earnings increased this year.', '她今年的收入增加了。'),
  ('5caa701d-0d82-43dd-b4db-79a4b68dd5b6-ex2', '5caa701d-0d82-43dd-b4db-79a4b68dd5b6', 'earnings', 'The restated earnings revealed years of premature revenue recognition.', '重述后的盈利数据揭示了多年来提前确认收入的做法。'),
  ('6eceddbf-7972-4f41-a7ca-3a8b5ae6ab72-ex1', '6eceddbf-7972-4f41-a7ca-3a8b5ae6ab72', 'oven', 'Preheat the oven to 180 degrees.', '把烤箱预热到180度。'),
  ('6eceddbf-7972-4f41-a7ca-3a8b5ae6ab72-ex2', '6eceddbf-7972-4f41-a7ca-3a8b5ae6ab72', 'oven', 'The energy labeling rules apply to every oven sold within the market.', '能效标签规则适用于市场上销售的每一台烤箱。'),
  ('63374990-18da-4e16-bd4b-49684bd592e2-ex1', '63374990-18da-4e16-bd4b-49684bd592e2', 'distinction', 'There is a clear distinction between the two.', '这两者之间有明显的区别。'),
  ('63374990-18da-4e16-bd4b-49684bd592e2-ex2', '63374990-18da-4e16-bd4b-49684bd592e2', 'distinction', 'The ruling draws a fine distinction between regulation and expropriation.', '该裁决在监管与征收之间作出了细致的区分。'),
  ('afdd6f93-da66-4ebc-80e1-eec7ab1b9edf-ex1', 'afdd6f93-da66-4ebc-80e1-eec7ab1b9edf', 'segment', 'The orange has ten segments.', '这个橙子有十瓣。'),
  ('afdd6f93-da66-4ebc-80e1-eec7ab1b9edf-ex2', 'afdd6f93-da66-4ebc-80e1-eec7ab1b9edf', 'segment', 'The luxury segment proved resilient even as mass-market demand collapsed.', '即使大众市场需求崩溃，奢侈品细分市场仍表现出韧性。'),
  ('7e39c5da-dc5a-45bd-9870-9a47d899a8d6-ex1', '7e39c5da-dc5a-45bd-9870-9a47d899a8d6', 'nowhere', 'The keys were nowhere to be found.', '钥匙哪儿都找不到。'),
  ('7e39c5da-dc5a-45bd-9870-9a47d899a8d6-ex2', '7e39c5da-dc5a-45bd-9870-9a47d899a8d6', 'nowhere', 'The negotiations went nowhere absent any willingness to compromise.', '在毫无妥协意愿的情况下，谈判毫无进展。'),
  ('58fa1288-13d4-482b-ac1f-4a654723f578-ex1', '58fa1288-13d4-482b-ac1f-4a654723f578', 'poet', 'The poet read her latest work.', '诗人朗读了她的最新作品。'),
  ('58fa1288-13d4-482b-ac1f-4a654723f578-ex2', '58fa1288-13d4-482b-ac1f-4a654723f578', 'poet', 'The poet''s estate disputed the unauthorized anthologizing of her verse.', '这位诗人的遗产管理方对其诗作被擅自选编提出异议。'),
  ('7079fd55-1328-47e8-bbd1-f8c26c03eba1-ex1', '7079fd55-1328-47e8-bbd1-f8c26c03eba1', 'mere', 'It was a mere coincidence.', '这只是个巧合。'),
  ('7079fd55-1328-47e8-bbd1-f8c26c03eba1-ex2', '7079fd55-1328-47e8-bbd1-f8c26c03eba1', 'mere', 'Mere negligence falls short of the recklessness the offense requires.', '单纯的过失尚未达到该罪所要求的轻率程度。'),
  ('6144c854-a421-4f65-aafa-8357fdd3262d-ex1', '6144c854-a421-4f65-aafa-8357fdd3262d', 'exciting', 'The game was very exciting.', '比赛非常激动人心。'),
  ('6144c854-a421-4f65-aafa-8357fdd3262d-ex2', '6144c854-a421-4f65-aafa-8357fdd3262d', 'exciting', 'The technology is exciting, yet its regulatory implications remain unsettled.', '这项技术令人振奋，但其监管影响仍悬而未决。'),
  ('5f67f17b-bc23-43ad-bf8f-f613f62e9f1a-ex1', '5f67f17b-bc23-43ad-bf8f-f613f62e9f1a', 'variation', 'There is some variation in the colors.', '颜色上有一些差异。'),
  ('5f67f17b-bc23-43ad-bf8f-f613f62e9f1a-ex2', '5f67f17b-bc23-43ad-bf8f-f613f62e9f1a', 'variation', 'Wide variation in enforcement undermines the regime''s claim to uniformity.', '执法上的巨大差异削弱了该制度声称的统一性。'),
  ('43152d82-d1c1-408c-8b5a-2f694b8cc4f5-ex1', '43152d82-d1c1-408c-8b5a-2f694b8cc4f5', 'comfort', 'The blanket gave the child comfort.', '毯子给了孩子安慰。'),
  ('43152d82-d1c1-408c-8b5a-2f694b8cc4f5-ex2', '43152d82-d1c1-408c-8b5a-2f694b8cc4f5', 'comfort', 'The remedies offer cold comfort to claimants facing protracted recovery.', '对于面临漫长追偿的索赔人来说，这些救济只是聊以慰藉。'),
  ('5015756c-86d2-43fe-a642-2b64ea67d54e-ex1', '5015756c-86d2-43fe-a642-2b64ea67d54e', 'radical', 'She has radical ideas about education.', '她对教育有激进的想法。'),
  ('5015756c-86d2-43fe-a642-2b64ea67d54e-ex2', '5015756c-86d2-43fe-a642-2b64ea67d54e', 'radical', 'The crisis prompted radical reform of the prudential framework.', '这场危机促成了审慎监管框架的根本性改革。'),
  ('1dd5f1e8-b6c5-4638-8629-5ad304d23d5d-ex1', '1dd5f1e8-b6c5-4638-8629-5ad304d23d5d', 'adapt', 'Animals adapt to their environment.', '动物会适应环境。'),
  ('1dd5f1e8-b6c5-4638-8629-5ad304d23d5d-ex2', '1dd5f1e8-b6c5-4638-8629-5ad304d23d5d', 'adapt', 'Regulators must adapt continuously as financial innovation outpaces the rules.', '随着金融创新超越规则，监管者必须不断调整适应。'),
  ('7150b979-66de-4cc9-a71d-737d66aa9dc5-ex1', '7150b979-66de-4cc9-a71d-737d66aa9dc5', 'Irish', 'He has Irish ancestors.', '他有爱尔兰祖先。'),
  ('7150b979-66de-4cc9-a71d-737d66aa9dc5-ex2', '7150b979-66de-4cc9-a71d-737d66aa9dc5', 'Irish', 'Irish courts referred the data transfer question to the European tribunal.', '爱尔兰法院将数据传输问题提交欧洲法庭裁决。'),
  ('74138d76-3853-4341-94e8-544c76b77d26-ex1', '74138d76-3853-4341-94e8-544c76b77d26', 'honey', 'I like honey in my tea.', '我喜欢在茶里加蜂蜜。'),
  ('74138d76-3853-4341-94e8-544c76b77d26-ex2', '74138d76-3853-4341-94e8-544c76b77d26', 'honey', 'The geographical indication protects honey produced within the designated region.', '地理标志保护在指定区域内生产的蜂蜜。'),
  ('b9922d89-c926-4043-a03f-296013881ee0-ex1', 'b9922d89-c926-4043-a03f-296013881ee0', 'correspondent', 'She is a foreign correspondent for the paper.', '她是这家报纸的驻外记者。'),
  ('b9922d89-c926-4043-a03f-296013881ee0-ex2', 'b9922d89-c926-4043-a03f-296013881ee0', 'correspondent', 'The funds transited correspondent accounts across three jurisdictions.', '这些资金经由三个司法管辖区的代理账户中转。'),
  ('f8151d77-b701-489e-9de6-baf7f767cb3e-ex1', 'f8151d77-b701-489e-9de6-baf7f767cb3e', 'pale', 'She looked pale after the long flight.', '长途飞行后她脸色苍白。'),
  ('f8151d77-b701-489e-9de6-baf7f767cb3e-ex2', 'f8151d77-b701-489e-9de6-baf7f767cb3e', 'pale', 'The remedies pale beside the magnitude of the documented harm.', '与已记录损害的规模相比，这些补救措施显得苍白无力。'),
  ('14dd6784-3539-4ad1-bc47-947b351c1cdd-ex1', '14dd6784-3539-4ad1-bc47-947b351c1cdd', 'musician', 'The musician played beautifully.', '这位音乐家演奏得很美。'),
  ('14dd6784-3539-4ad1-bc47-947b351c1cdd-ex2', '14dd6784-3539-4ad1-bc47-947b351c1cdd', 'musician', 'The musician''s contract assigned streaming royalties on terms now disputed.', '这位音乐家的合同就流媒体版税作出了如今备受争议的约定。'),
  ('d1ba812d-eaa5-493d-8f13-397c7725a4a8-ex1', 'd1ba812d-eaa5-493d-8f13-397c7725a4a8', 'significance', 'The discovery has great significance.', '这一发现意义重大。'),
  ('d1ba812d-eaa5-493d-8f13-397c7725a4a8-ex2', 'd1ba812d-eaa5-493d-8f13-397c7725a4a8', 'significance', 'The ruling''s significance extends to every contract drafted on similar terms.', '该裁决的意义波及所有按类似条款起草的合同。'),
  ('0ef1c9cf-d73b-4717-b0c6-2545d251fcfa-ex1', '0ef1c9cf-d73b-4717-b0c6-2545d251fcfa', 'vessel', 'The vessel sailed into the harbor.', '船驶入了港口。'),
  ('0ef1c9cf-d73b-4717-b0c6-2545d251fcfa-ex2', '0ef1c9cf-d73b-4717-b0c6-2545d251fcfa', 'vessel', 'The flag state bears responsibility for every vessel on its registry.', '船旗国对其登记册上的每艘船舶负有责任。'),
  ('7082474c-b9e5-4a57-87cb-3012c7e9d9e2-ex1', '7082474c-b9e5-4a57-87cb-3012c7e9d9e2', 'storage', 'We need more storage for our files.', '我们需要更多空间来存放文件。'),
  ('7082474c-b9e5-4a57-87cb-3012c7e9d9e2-ex2', '7082474c-b9e5-4a57-87cb-3012c7e9d9e2', 'storage', 'The storage facility operates under continuous regulatory monitoring.', '该储存设施在持续的监管监测下运营。'),
  ('17661308-32f7-4143-9846-953f0d44cf91-ex1', '17661308-32f7-4143-9846-953f0d44cf91', 'flee', 'The villagers had to flee the flood.', '村民们不得不逃离洪水。'),
  ('17661308-32f7-4143-9846-953f0d44cf91-ex2', '17661308-32f7-4143-9846-953f0d44cf91', 'flee', 'The directors elected to flee jurisdiction rather than face the inquiry.', '董事们选择逃离管辖区，而非面对调查。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('f302546d-460f-494d-b758-0f32e05ddda7-ex1', 'f302546d-460f-494d-b758-0f32e05ddda7', 'mm-hmm', '"Are you coming?" "Mm-hmm."', '“你来吗？”“嗯。”'),
  ('f302546d-460f-494d-b758-0f32e05ddda7-ex2', 'f302546d-460f-494d-b758-0f32e05ddda7', 'mm-hmm', 'A noncommittal "mm-hmm" in negotiation seldom binds a party to anything.', '谈判中一句含糊的“嗯哼”几乎从不构成对当事方的任何约束。'),
  ('8430bdc4-2c4c-4972-ab0c-690d83b51672-ex1', '8430bdc4-2c4c-4972-ab0c-690d83b51672', 'leather', 'He bought a brown leather wallet.', '他买了一个棕色皮夹。'),
  ('8430bdc4-2c4c-4972-ab0c-690d83b51672-ex2', '8430bdc4-2c4c-4972-ab0c-690d83b51672', 'leather', 'The seized leather goods bore counterfeit marks of protected brands.', '查获的皮具带有受保护品牌的假冒标识。'),
  ('40d7d6d7-2417-4f7b-a37e-9d284a6d2c36-ex1', '40d7d6d7-2417-4f7b-a37e-9d284a6d2c36', 'distribute', 'The teacher distributed the worksheets.', '老师分发了练习题。'),
  ('40d7d6d7-2417-4f7b-a37e-9d284a6d2c36-ex2', '40d7d6d7-2417-4f7b-a37e-9d284a6d2c36', 'distribute', 'The trustee shall distribute the residue equally among the named beneficiaries.', '受托人应将剩余财产在指定受益人之间平均分配。'),
  ('47b63f29-48b1-401c-8cfa-3f1cc1db004a-ex1', '47b63f29-48b1-401c-8cfa-3f1cc1db004a', 'evolution', 'We learned about the evolution of birds.', '我们学习了鸟类的进化。'),
  ('47b63f29-48b1-401c-8cfa-3f1cc1db004a-ex2', '47b63f29-48b1-401c-8cfa-3f1cc1db004a', 'evolution', 'The doctrine''s evolution reflects shifting judicial attitudes toward delegation.', '这一原则的演变反映了司法对授权态度的转变。'),
  ('e921a868-0802-4075-a018-9833da6bb593-ex1', 'e921a868-0802-4075-a018-9833da6bb593', 'ill', 'She felt ill after lunch.', '午饭后她感到不舒服。'),
  ('e921a868-0802-4075-a018-9833da6bb593-ex2', 'e921a868-0802-4075-a018-9833da6bb593', 'ill', 'The institution was ill equipped to administer the expanded mandate.', '该机构根本无力履行扩大后的职权。'),
  ('c5cf4c03-eb49-4f38-9ebf-39e5837b5abe-ex1', 'c5cf4c03-eb49-4f38-9ebf-39e5837b5abe', 'tribe', 'The tribe has lived here for centuries.', '这个部落在这里生活了几个世纪。'),
  ('c5cf4c03-eb49-4f38-9ebf-39e5837b5abe-ex2', 'c5cf4c03-eb49-4f38-9ebf-39e5837b5abe', 'tribe', 'The settlement recognizes the tribe''s sovereign authority over ancestral lands.', '和解协议承认该部落对祖传土地的主权权力。'),
  ('8501f6e0-dd6c-49c6-9622-8fc4ae12dce8-ex1', '8501f6e0-dd6c-49c6-9622-8fc4ae12dce8', 'shelf', 'Put the book back on the shelf.', '把书放回架子上。'),
  ('8501f6e0-dd6c-49c6-9622-8fc4ae12dce8-ex2', '8501f6e0-dd6c-49c6-9622-8fc4ae12dce8', 'shelf', 'The proposal sat on the shelf for years before circumstances revived it.', '这一提案被搁置多年，直到形势变化才重见天日。'),
  ('9aa601f4-cecc-4536-b79e-c6658da2aa12-ex1', '9aa601f4-cecc-4536-b79e-c6658da2aa12', 'grandfather', 'My grandfather grew up on a farm.', '我祖父在农场长大。'),
  ('9aa601f4-cecc-4536-b79e-c6658da2aa12-ex2', '9aa601f4-cecc-4536-b79e-c6658da2aa12', 'grandfather', 'The statute grandfathers existing operators under the prior, more lenient rules.', '该法规对现有经营者按此前较宽松的规则予以既往不咎的豁免。'),
  ('cf2090c6-3c8d-4a2e-95c1-040a5bd75d80-ex1', 'cf2090c6-3c8d-4a2e-95c1-040a5bd75d80', 'lawn', 'He mows the lawn every weekend.', '他每个周末都修剪草坪。'),
  ('cf2090c6-3c8d-4a2e-95c1-040a5bd75d80-ex2', 'cf2090c6-3c8d-4a2e-95c1-040a5bd75d80', 'lawn', 'Watering bans during the drought extended to private lawns and gardens.', '干旱期间的用水禁令也延伸到了私人草坪和花园。'),
  ('a8f6f2f6-f696-4138-b0e5-a0320a462993-ex1', 'a8f6f2f6-f696-4138-b0e5-a0320a462993', 'buyer', 'The buyer paid in cash.', '买家用现金付款。'),
  ('a8f6f2f6-f696-4138-b0e5-a0320a462993-ex2', 'a8f6f2f6-f696-4138-b0e5-a0320a462993', 'buyer', 'The buyer assumed disclosed liabilities while the seller retained the contingent ones.', '买方承接已披露的负债，卖方则保留或有负债。'),
  ('ce2e0bad-93df-49f6-a496-cfb11e66b950-ex1', 'ce2e0bad-93df-49f6-a496-cfb11e66b950', 'dining', 'We ate in the hotel''s dining room.', '我们在酒店餐厅用餐。'),
  ('ce2e0bad-93df-49f6-a496-cfb11e66b950-ex2', 'ce2e0bad-93df-49f6-a496-cfb11e66b950', 'dining', 'The food safety code applies to every commercial dining establishment.', '食品安全规范适用于每一家商业餐饮场所。'),
  ('7c2326f9-b710-4726-bbb6-51781f6c2b6d-ex1', '7c2326f9-b710-4726-bbb6-51781f6c2b6d', 'wisdom', 'With age comes wisdom.', '随着年龄增长，人会变得睿智。'),
  ('7c2326f9-b710-4726-bbb6-51781f6c2b6d-ex2', '7c2326f9-b710-4726-bbb6-51781f6c2b6d', 'wisdom', 'The court questioned the wisdom of delegating enforcement to private auditors.', '法院质疑将执法委托给私营审计机构是否明智。'),
