  ('ef6d3ef5-a5f3-46ca-a591-dc904b50d2f2-ex1', 'ef6d3ef5-a5f3-46ca-a591-dc904b50d2f2', 'narrative', 'The film tells a moving narrative.', '这部电影讲述了一个感人的故事。'),
  ('ef6d3ef5-a5f3-46ca-a591-dc904b50d2f2-ex2', 'ef6d3ef5-a5f3-46ca-a591-dc904b50d2f2', 'narrative', 'The official narrative diverged sharply from the contemporaneous documentary record.', '官方叙述与当时的书面记录存在严重出入。'),
  ('dae41678-f3aa-4a7b-9030-ba9f3e975cde-ex1', 'dae41678-f3aa-4a7b-9030-ba9f3e975cde', 'photographer', 'The photographer took beautiful pictures.', '摄影师拍了很美的照片。'),
