  ('37dbde4f-08a0-4f4a-bc52-9a083979a674-ex1', '37dbde4f-08a0-4f4a-bc52-9a083979a674', 'prompt', 'Thank you for your prompt reply.', '谢谢你的及时回复。'),
  ('37dbde4f-08a0-4f4a-bc52-9a083979a674-ex2', '37dbde4f-08a0-4f4a-bc52-9a083979a674', 'prompt', 'The disclosures prompted parallel investigations across three jurisdictions.', '这些披露引发了三个司法管辖区的并行调查。'),
  ('ac261f0c-a5d4-48c2-9f26-873c1f3a4f18-ex1', 'ac261f0c-a5d4-48c2-9f26-873c1f3a4f18', 'cholesterol', 'High cholesterol is bad for the heart.', '高胆固醇对心脏有害。'),
  ('ac261f0c-a5d4-48c2-9f26-873c1f3a4f18-ex2', 'ac261f0c-a5d4-48c2-9f26-873c1f3a4f18', 'cholesterol', 'The labeling rules require disclosure of cholesterol content per serving.', '标签规则要求披露每份食品的胆固醇含量。'),
