  ('b1f584c6-0469-4632-868b-fa3a0ae8f2da-ex2', 'b1f584c6-0469-4632-868b-fa3a0ae8f2da', 'sue', 'The shareholders sued the directors for breach of fiduciary duty.', '股东以违反信义义务为由起诉了董事。'),
  ('a9cae194-8925-46c3-9aad-53a07de1a658-ex1', 'a9cae194-8925-46c3-9aad-53a07de1a658', 'flavor', 'This ice cream has a rich flavor.', '这款冰淇淋味道浓郁。'),
  ('a9cae194-8925-46c3-9aad-53a07de1a658-ex2', 'a9cae194-8925-46c3-9aad-53a07de1a658', 'flavor', 'The proceedings acquired a distinctly political flavor as the election neared.', '随着选举临近，这些诉讼染上了明显的政治色彩。'),
  ('dcf8a136-6016-4bbe-986f-822629821cad-ex1', 'dcf8a136-6016-4bbe-986f-822629821cad', 'overlook', 'The hotel room overlooks the sea.', '酒店房间可以俯瞰大海。'),
  ('dcf8a136-6016-4bbe-986f-822629821cad-ex2', 'dcf8a136-6016-4bbe-986f-822629821cad', 'overlook', 'The auditors overlooked discrepancies that any rigorous review would have caught.', '审计师忽视了任何严谨审查都会发现的差异。'),
  ('b69857da-263c-46bd-a919-1b4fa3a50bfb-ex1', 'b69857da-263c-46bd-a919-1b4fa3a50bfb', 'float', 'The leaf floats on the water.', '叶子漂在水面上。'),
  ('b69857da-263c-46bd-a919-1b4fa3a50bfb-ex2', 'b69857da-263c-46bd-a919-1b4fa3a50bfb', 'float', 'The decision to float the currency unleashed severe and immediate volatility.', '实行货币自由浮动的决定立即引发了剧烈波动。'),
  ('c653d785-a3b7-463d-ab70-ebbcf470e132-ex1', 'c653d785-a3b7-463d-ab70-ebbcf470e132', 'undergo', 'She will undergo surgery next week.', '她下周要接受手术。'),
  ('c653d785-a3b7-463d-ab70-ebbcf470e132-ex2', 'c653d785-a3b7-463d-ab70-ebbcf470e132', 'undergo', 'Every certified facility must undergo annual independent inspection.', '每个获认证的设施都必须接受年度独立检查。'),
  ('b06e071f-3bb3-4933-a73a-c9184c5ccb6c-ex1', 'b06e071f-3bb3-4933-a73a-c9184c5ccb6c', 'sequence', 'Follow the steps in sequence.', '按顺序执行这些步骤。'),
  ('b06e071f-3bb3-4933-a73a-c9184c5ccb6c-ex2', 'b06e071f-3bb3-4933-a73a-c9184c5ccb6c', 'sequence', 'The inquiry reconstructed the sequence of events preceding the collapse.', '调查还原了崩塌前的一系列事件经过。'),
  ('57d26570-48a6-4c6c-a341-877a0354a9ec-ex1', '57d26570-48a6-4c6c-a341-877a0354a9ec', 'demonstration', 'The teacher gave a cooking demonstration.', '老师做了烹饪演示。'),
  ('57d26570-48a6-4c6c-a341-877a0354a9ec-ex2', '57d26570-48a6-4c6c-a341-877a0354a9ec', 'demonstration', 'The peaceful demonstration was met with disproportionate force.', '和平示威遭到了不相称的武力对待。'),
  ('db0113cb-5a19-42d6-96f5-4dbe42b320c8-ex1', 'db0113cb-5a19-42d6-96f5-4dbe42b320c8', 'jet', 'The jet took off on time.', '喷气式飞机准时起飞。'),
  ('db0113cb-5a19-42d6-96f5-4dbe42b320c8-ex2', 'db0113cb-5a19-42d6-96f5-4dbe42b320c8', 'jet', 'The corporate jet''s undisclosed use featured prominently in the misconduct findings.', '公务机未披露的使用情况在不当行为认定中尤为突出。'),
  ('c7998406-4c69-45d2-8a89-47dac84b5071-ex1', 'c7998406-4c69-45d2-8a89-47dac84b5071', 'orange', 'I drink orange juice every morning.', '我每天早上喝橙汁。'),
  ('c7998406-4c69-45d2-8a89-47dac84b5071-ex2', 'c7998406-4c69-45d2-8a89-47dac84b5071', 'orange', 'The orange export quotas became a flashpoint in the trade negotiation.', '橙子出口配额成了贸易谈判的引爆点。'),
  ('0a8e15c1-0f48-4c43-aaa8-cc3b9d7ab093-ex1', '0a8e15c1-0f48-4c43-aaa8-cc3b9d7ab093', 'consumption', 'Reduce your sugar consumption.', '减少糖的摄入。'),
  ('0a8e15c1-0f48-4c43-aaa8-cc3b9d7ab093-ex2', '0a8e15c1-0f48-4c43-aaa8-cc3b9d7ab093', 'consumption', 'Per capita consumption continued to rise despite repeated conservation appeals.', '尽管多次呼吁节约，人均消费量仍持续上升。'),
  ('ef3c4b0e-5ca3-45fd-a411-e34077a5e185-ex1', 'ef3c4b0e-5ca3-45fd-a411-e34077a5e185', 'assert', 'She asserted that she was right.', '她坚称自己是对的。'),
  ('ef3c4b0e-5ca3-45fd-a411-e34077a5e185-ex2', 'ef3c4b0e-5ca3-45fd-a411-e34077a5e185', 'assert', 'The claimants assert rights the issuer expressly disclaimed in the prospectus.', '索赔人主张的权利正是发行人在招股书中明确否认的。'),
  ('981a4190-c8b9-4525-ae52-10de8e2c9634-ex1', '981a4190-c8b9-4525-ae52-10de8e2c9634', 'blade', 'The knife has a sharp blade.', '这把刀刀刃锋利。'),
  ('981a4190-c8b9-4525-ae52-10de8e2c9634-ex2', '981a4190-c8b9-4525-ae52-10de8e2c9634', 'blade', 'The turbine blades were replaced under the remediation schedule''s terms.', '涡轮叶片已按整改时间表的条款进行了更换。'),
  ('421d6288-dad2-47a1-8f5f-5e4d4c9e3fd4-ex1', '421d6288-dad2-47a1-8f5f-5e4d4c9e3fd4', 'temporary', 'This is just a temporary solution.', '这只是一个临时的解决办法。'),
  ('421d6288-dad2-47a1-8f5f-5e4d4c9e3fd4-ex2', '421d6288-dad2-47a1-8f5f-5e4d4c9e3fd4', 'temporary', 'The temporary measures were extended pending a review of their proportionality.', '在对其相称性进行审查之前，临时措施获得延长。'),
  ('9b11dc65-f2ac-4920-8248-9ea51d9c64db-ex1', '9b11dc65-f2ac-4920-8248-9ea51d9c64db', 'medication', 'Take your medication after meals.', '饭后服药。'),
  ('9b11dc65-f2ac-4920-8248-9ea51d9c64db-ex2', '9b11dc65-f2ac-4920-8248-9ea51d9c64db', 'medication', 'The recall covered every batch of the medication from the implicated facility.', '召回涵盖了涉事工厂生产的每一批该药物。'),
  ('03fe8480-48c5-4aa9-83ec-34490224e3e6-ex1', '03fe8480-48c5-4aa9-83ec-34490224e3e6', 'cabin', 'We stayed in a small cabin in the woods.', '我们住在林中的一间小木屋里。'),
  ('03fe8480-48c5-4aa9-83ec-34490224e3e6-ex2', '03fe8480-48c5-4aa9-83ec-34490224e3e6', 'cabin', 'The cabin pressurization failure prompted a comprehensive fleet inspection.', '客舱增压故障引发了全机队的全面检查。'),
  ('621ff5ae-76f8-4084-b50b-988e6c599b02-ex1', '621ff5ae-76f8-4084-b50b-988e6c599b02', 'bite', 'The dog gave me a small bite.', '那只狗轻轻咬了我一下。'),
  ('621ff5ae-76f8-4084-b50b-988e6c599b02-ex2', '621ff5ae-76f8-4084-b50b-988e6c599b02', 'bite', 'Reputational sanctions often bite harder than formal regulatory penalties.', '声誉制裁的杀伤力往往比正式监管处罚更大。'),
  ('bd87585f-3e17-4dfd-a5a0-35277facaed0-ex1', 'bd87585f-3e17-4dfd-a5a0-35277facaed0', 'edition', 'I bought the latest edition of the book.', '我买了这本书的最新版。'),
  ('bd87585f-3e17-4dfd-a5a0-35277facaed0-ex2', 'bd87585f-3e17-4dfd-a5a0-35277facaed0', 'edition', 'The revised edition corrected errors that had propagated through earlier printings.', '修订版纠正了在早期印次中流传的错误。'),
  ('2b67660a-74c3-42d1-bb4c-5bcd19f406e2-ex1', '2b67660a-74c3-42d1-bb4c-5bcd19f406e2', 'valley', 'The village lies in a green valley.', '村庄坐落在绿色的山谷中。'),
  ('2b67660a-74c3-42d1-bb4c-5bcd19f406e2-ex2', '2b67660a-74c3-42d1-bb4c-5bcd19f406e2', 'valley', 'The transboundary valley''s water resources are governed by a joint commission.', '这条跨境山谷的水资源由一个联合委员会管理。'),
  ('49ff4abd-f007-43fc-b69a-d987bb0b0f45-ex1', '49ff4abd-f007-43fc-b69a-d987bb0b0f45', 'yours', 'Is this umbrella yours?', '这把伞是你的吗？'),
  ('49ff4abd-f007-43fc-b69a-d987bb0b0f45-ex2', '49ff4abd-f007-43fc-b69a-d987bb0b0f45', 'yours', 'The royalties accruing under the patent are yours alone to administer.', '该专利项下产生的使用费由你独自支配。'),
  ('9e6dd41b-8d98-4929-8378-c7392929990e-ex1', '9e6dd41b-8d98-4929-8378-c7392929990e', 'pitch', 'The players ran onto the pitch.', '球员们跑上了球场。'),
  ('9e6dd41b-8d98-4929-8378-c7392929990e-ex2', '9e6dd41b-8d98-4929-8378-c7392929990e', 'pitch', 'The startup''s investor pitch overstated revenue the audit later corrected.', '这家初创公司向投资者的路演夸大了后来被审计纠正的收入。'),
  ('36878a8b-a6ab-43f2-ae5d-1cc799610952-ex1', '36878a8b-a6ab-43f2-ae5d-1cc799610952', 'pine', 'The forest is full of pine trees.', '森林里满是松树。'),
  ('36878a8b-a6ab-43f2-ae5d-1cc799610952-ex2', '36878a8b-a6ab-43f2-ae5d-1cc799610952', 'pine', 'The ordinance prohibits felling protected pine without municipal authorization.', '该条例禁止未经市政许可砍伐受保护的松树。'),
  ('79b75101-5d41-4639-96d9-f53f0beacb20-ex1', '79b75101-5d41-4639-96d9-f53f0beacb20', 'brilliant', 'That was a brilliant idea!', '那是个绝妙的主意！'),
  ('79b75101-5d41-4639-96d9-f53f0beacb20-ex2', '79b75101-5d41-4639-96d9-f53f0beacb20', 'brilliant', 'The brilliant structuring concealed risks that ultimately proved fatal.', '这种精巧的架构掩盖了最终致命的风险。'),
  ('85bdac89-d06e-434f-8dde-49f60b615b0c-ex1', '85bdac89-d06e-434f-8dde-49f60b615b0c', 'versus', 'It''s our team versus theirs tomorrow.', '明天是我们队对他们队。'),
  ('85bdac89-d06e-434f-8dde-49f60b615b0c-ex2', '85bdac89-d06e-434f-8dde-49f60b615b0c', 'versus', 'The landmark case of the regulator versus the conglomerate redefined the doctrine.', '监管机构诉该集团的标志性案件重新定义了这一法律原则。'),
  ('9adceb4a-9c48-4950-b718-84e2ff0b8bd9-ex1', '9adceb4a-9c48-4950-b718-84e2ff0b8bd9', 'manufacturing', 'The town depends on manufacturing.', '这个镇依赖制造业。'),
  ('9adceb4a-9c48-4950-b718-84e2ff0b8bd9-ex2', '9adceb4a-9c48-4950-b718-84e2ff0b8bd9', 'manufacturing', 'Manufacturing employment declined as production migrated offshore.', '随着生产迁往海外，制造业就业人数下降。'),
  ('81ba50d4-6ca0-40ff-be8b-428d50c00f48-ex1', '81ba50d4-6ca0-40ff-be8b-428d50c00f48', 'absolute', 'I have absolute trust in you.', '我对你绝对信任。'),
  ('81ba50d4-6ca0-40ff-be8b-428d50c00f48-ex2', '81ba50d4-6ca0-40ff-be8b-428d50c00f48', 'absolute', 'No right is absolute; each yields to narrowly drawn and proportionate limits.', '没有任何权利是绝对的，每项权利都受严格限定且相称的限制约束。'),
  ('527a2e1e-c35b-4727-ae69-6b544fce5dba-ex1', '527a2e1e-c35b-4727-ae69-6b544fce5dba', 'chef', 'The chef prepared a wonderful meal.', '厨师准备了一顿美味佳肴。'),
  ('527a2e1e-c35b-4727-ae69-6b544fce5dba-ex2', '527a2e1e-c35b-4727-ae69-6b544fce5dba', 'chef', 'The celebrity chef''s restaurant group entered administration amid mounting losses.', '这位名厨的餐饮集团在亏损不断扩大中进入了破产管理程序。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('979de620-cb25-4eb6-9d17-abdf13d4c4e1-ex1', '979de620-cb25-4eb6-9d17-abdf13d4c4e1', 'discrimination', 'The law forbids discrimination at work.', '法律禁止工作场所的歧视。'),
  ('979de620-cb25-4eb6-9d17-abdf13d4c4e1-ex2', '979de620-cb25-4eb6-9d17-abdf13d4c4e1', 'discrimination', 'The commission documented systemic discrimination in mortgage approval rates.', '委员会记录了房贷审批率中的系统性歧视。'),
  ('9e80de5d-9c46-4a91-af26-29b328ab1311-ex1', '9e80de5d-9c46-4a91-af26-29b328ab1311', 'offensive', 'His joke was rather offensive.', '他的笑话相当冒犯人。'),
  ('9e80de5d-9c46-4a91-af26-29b328ab1311-ex2', '9e80de5d-9c46-4a91-af26-29b328ab1311', 'offensive', 'The team launched an offensive that overwhelmed its rival''s market position.', '该团队发起的攻势压垮了对手的市场地位。'),
  ('cb3f782f-9514-4cc2-a193-ea6093d8271a-ex1', 'cb3f782f-9514-4cc2-a193-ea6093d8271a', 'boom', 'The town had a tourism boom.', '这个镇经历了旅游业的繁荣。'),
  ('cb3f782f-9514-4cc2-a193-ea6093d8271a-ex2', 'cb3f782f-9514-4cc2-a193-ea6093d8271a', 'boom', 'The credit boom sowed the imbalances that the ensuing bust exposed.', '信贷繁荣埋下了随后崩盘所暴露的失衡。'),
  ('7bca4cbf-13f0-4dc7-a21a-d91e91a6361f-ex1', '7bca4cbf-13f0-4dc7-a21a-d91e91a6361f', 'register', 'Please register at the front desk.', '请在前台登记。'),
  ('7bca4cbf-13f0-4dc7-a21a-d91e91a6361f-ex2', '7bca4cbf-13f0-4dc7-a21a-d91e91a6361f', 'register', 'Every beneficial owner must register under the transparency statute.', '根据透明度法规，每个受益所有人都必须登记。'),
  ('f0fa2b09-4c2d-446c-bbe2-93be86d07ed6-ex1', 'f0fa2b09-4c2d-446c-bbe2-93be86d07ed6', 'appoint', 'They appointed her as team leader.', '他们任命她为组长。'),
  ('f0fa2b09-4c2d-446c-bbe2-93be86d07ed6-ex2', 'f0fa2b09-4c2d-446c-bbe2-93be86d07ed6', 'appoint', 'The court appointed an independent administrator to manage the insolvent estate.', '法院指定了一名独立管理人来管理破产财产。'),
  ('838f5eaf-59d3-4104-9ae2-be5846cf1875-ex1', '838f5eaf-59d3-4104-9ae2-be5846cf1875', 'heritage', 'The castle is part of our heritage.', '这座城堡是我们遗产的一部分。'),
  ('838f5eaf-59d3-4104-9ae2-be5846cf1875-ex2', '838f5eaf-59d3-4104-9ae2-be5846cf1875', 'heritage', 'The convention obliges states to safeguard cultural heritage within their borders.', '该公约要求各国保护其境内的文化遗产。'),
  ('b55b33b0-c2d5-49b0-8543-1eedf734bf64-ex1', 'b55b33b0-c2d5-49b0-8543-1eedf734bf64', 'God', 'She prayed to God for help.', '她向上帝祈求帮助。'),
  ('b55b33b0-c2d5-49b0-8543-1eedf734bf64-ex2', 'b55b33b0-c2d5-49b0-8543-1eedf734bf64', 'God', 'The constitution forbids the establishment of any official conception of God.', '宪法禁止确立任何官方的神明观念。'),
  ('b0d5372c-03bf-48a2-bfe9-ee017b1ec060-ex1', 'b0d5372c-03bf-48a2-bfe9-ee017b1ec060', 'dominant', 'Red is the dominant color in the room.', '红色是这个房间的主色调。'),
  ('b0d5372c-03bf-48a2-bfe9-ee017b1ec060-ex2', 'b0d5372c-03bf-48a2-bfe9-ee017b1ec060', 'dominant', 'The firm abused its dominant position to exclude smaller competitors.', '该公司滥用其支配地位排挤较小的竞争者。'),
  ('c130de32-3a84-46dc-9b7b-9c44a24fa8b2-ex1', 'c130de32-3a84-46dc-9b7b-9c44a24fa8b2', 'successfully', 'She successfully passed the exam.', '她顺利通过了考试。'),
  ('c130de32-3a84-46dc-9b7b-9c44a24fa8b2-ex2', 'c130de32-3a84-46dc-9b7b-9c44a24fa8b2', 'successfully', 'The defense successfully excluded evidence obtained without valid authorization.', '辩方成功排除了未经有效授权获取的证据。'),
  ('bec24eed-7ae4-43f0-9fac-ac6274da5358-ex1', 'bec24eed-7ae4-43f0-9fac-ac6274da5358', 'shit', '"Oh, shit," he muttered, dropping the keys.', '“糟了，”他嘟囔着，钥匙掉了。'),
  ('bec24eed-7ae4-43f0-9fac-ac6274da5358-ex2', 'bec24eed-7ae4-43f0-9fac-ac6274da5358', 'shit', 'Investigators waded through what one called a shitstorm of falsified records.', '调查人员费力地处理了一位调查员所称的造假记录的烂摊子。'),
  ('f9e7d090-6828-43c2-a125-487cbe255760-ex1', 'f9e7d090-6828-43c2-a125-487cbe255760', 'lemon', 'Add a slice of lemon to the water.', '在水里加一片柠檬。'),
  ('f9e7d090-6828-43c2-a125-487cbe255760-ex2', 'f9e7d090-6828-43c2-a125-487cbe255760', 'lemon', 'The car proved a lemon, prompting a claim under the consumer warranty.', '这辆车问题不断，促使车主依据消费者保修条款提出索赔。'),
  ('747f6b3f-1bc4-4cdb-b229-160b5b07c729-ex1', '747f6b3f-1bc4-4cdb-b229-160b5b07c729', 'hungry', 'I am hungry; let''s eat.', '我饿了，我们去吃饭吧。'),
  ('747f6b3f-1bc4-4cdb-b229-160b5b07c729-ex2', '747f6b3f-1bc4-4cdb-b229-160b5b07c729', 'hungry', 'Capital hungry for yield ignored the credit risk embedded in the structure.', '渴求收益的资本忽视了这一结构中蕴含的信用风险。'),
  ('27d2a90c-fc29-4e9d-aa67-14af44db833b-ex1', '27d2a90c-fc29-4e9d-aa67-14af44db833b', 'wander', 'We wandered through the old streets.', '我们在老街上闲逛。'),
  ('27d2a90c-fc29-4e9d-aa67-14af44db833b-ex2', '27d2a90c-fc29-4e9d-aa67-14af44db833b', 'wander', 'The argument wandered far from the narrow question the court had to decide.', '论证远远偏离了法院需要裁决的那个具体问题。'),
  ('2dcac735-9691-4991-b356-285ce89cefe7-ex1', '2dcac735-9691-4991-b356-285ce89cefe7', 'submit', 'Please submit your form by Friday.', '请在周五前提交表格。'),
  ('2dcac735-9691-4991-b356-285ce89cefe7-ex2', '2dcac735-9691-4991-b356-285ce89cefe7', 'submit', 'The parties agreed to submit unresolved disputes to binding arbitration.', '双方同意将未决争议提交有约束力的仲裁。'),
  ('256ae5dc-f477-42b8-ac26-9b1bb99d9884-ex1', '256ae5dc-f477-42b8-ac26-9b1bb99d9884', 'economics', 'She is studying economics.', '她在学习经济学。'),
  ('256ae5dc-f477-42b8-ac26-9b1bb99d9884-ex2', '256ae5dc-f477-42b8-ac26-9b1bb99d9884', 'economics', 'The economics of the scheme collapsed once the subsidies were withdrawn.', '补贴一旦取消，该方案的经济基础便随之崩溃。'),
  ('b24dc132-3cf5-4f02-ab2d-ed6f6c49921e-ex1', 'b24dc132-3cf5-4f02-ab2d-ed6f6c49921e', 'naked', 'The baby ran around naked.', '宝宝光着身子跑来跑去。'),
  ('b24dc132-3cf5-4f02-ab2d-ed6f6c49921e-ex2', 'b24dc132-3cf5-4f02-ab2d-ed6f6c49921e', 'naked', 'The figures were visible to the naked eye as plainly irreconcilable.', '这些数字肉眼可见地明显对不上。'),
  ('90c8fbe1-f813-43bf-8621-fa813dc1b180-ex1', '90c8fbe1-f813-43bf-8621-fa813dc1b180', 'anticipate', 'We anticipate a busy weekend.', '我们预计周末会很忙。'),
