  ('587ca3ee-ee43-47a0-8738-c8bbea009edb-ex2', '587ca3ee-ee43-47a0-8738-c8bbea009edb', 'seize', 'Authorities may seize assets traceable to the proceeds of the offense.', '当局可以查封可追溯为犯罪所得的资产。'),
  ('9b898e3d-1876-4645-9914-d3ed132ce598-ex1', '9b898e3d-1876-4645-9914-d3ed132ce598', 'ethics', 'Medical ethics protect patients.', '医学伦理保护患者。'),
  ('9b898e3d-1876-4645-9914-d3ed132ce598-ex2', '9b898e3d-1876-4645-9914-d3ed132ce598', 'ethics', 'The ethics code requires officials to recuse themselves from conflicted matters.', '道德准则要求官员在利益冲突事项中回避。'),
  ('a4d7e5e0-10d8-417a-812e-b1b791fbce64-ex1', 'a4d7e5e0-10d8-417a-812e-b1b791fbce64', 'nomination', 'She received a nomination for the award.', '她获得了该奖项的提名。'),
  ('a4d7e5e0-10d8-417a-812e-b1b791fbce64-ex2', 'a4d7e5e0-10d8-417a-812e-b1b791fbce64', 'nomination', 'The nomination stalled in committee amid bipartisan reservations.', '这项提名因两党的保留意见而在委员会搁浅。'),
  ('7fca1af0-1e4a-42f7-a459-b013acd8460c-ex1', '7fca1af0-1e4a-42f7-a459-b013acd8460c', 'permission', 'You need permission to enter.', '进入需要许可。'),
  ('7fca1af0-1e4a-42f7-a459-b013acd8460c-ex2', '7fca1af0-1e4a-42f7-a459-b013acd8460c', 'permission', 'No structural alteration may proceed without the authority''s prior permission.', '未经主管部门事先许可，不得进行任何结构性改动。'),
  ('0fbbbdd3-4ac3-48ce-bddd-e03f760dd7ae-ex1', '0fbbbdd3-4ac3-48ce-bddd-e03f760dd7ae', 'wise', 'It was a wise decision.', '那是个明智的决定。'),
  ('0fbbbdd3-4ac3-48ce-bddd-e03f760dd7ae-ex2', '0fbbbdd3-4ac3-48ce-bddd-e03f760dd7ae', 'wise', 'The court questioned whether it was wise to delegate enforcement to private parties.', '法院质疑将执法委托给私人主体是否明智。'),
  ('0138b24b-02bb-41aa-ba54-6efc1dd95503-ex1', '0138b24b-02bb-41aa-ba54-6efc1dd95503', 'actress', 'The actress won an award.', '这位女演员获了奖。'),
  ('0138b24b-02bb-41aa-ba54-6efc1dd95503-ex2', '0138b24b-02bb-41aa-ba54-6efc1dd95503', 'actress', 'The actress''s estate litigated the streaming royalties for nearly a decade.', '这位女演员的遗产管理方就流媒体版税诉讼了将近十年。'),
  ('40c6c0ba-32a4-436c-937f-c34d883eab80-ex1', '40c6c0ba-32a4-436c-937f-c34d883eab80', 'summit', 'We reached the summit at noon.', '我们中午登上了顶峰。'),
  ('40c6c0ba-32a4-436c-937f-c34d883eab80-ex2', '40c6c0ba-32a4-436c-937f-c34d883eab80', 'summit', 'The summit produced binding commitments on emission reduction targets.', '此次峰会产生了关于减排目标的约束性承诺。'),
  ('0e63d8da-9fa3-4922-971b-613e25bf8838-ex1', '0e63d8da-9fa3-4922-971b-613e25bf8838', 'acid', 'Lemon juice is mildly acidic.', '柠檬汁略带酸性。'),
  ('0e63d8da-9fa3-4922-971b-613e25bf8838-ex2', '0e63d8da-9fa3-4922-971b-613e25bf8838', 'acid', 'The acid test of the reforms is whether enforcement keeps pace with evasion.', '这些改革的真正考验在于执法能否跟上规避的步伐。'),
  ('b3ef33a4-8fb9-4cd3-a89e-29bf32ca9814-ex1', 'b3ef33a4-8fb9-4cd3-a89e-29bf32ca9814', 'odds', 'The odds of winning are very low.', '获胜的几率很低。'),
  ('b3ef33a4-8fb9-4cd3-a89e-29bf32ca9814-ex2', 'b3ef33a4-8fb9-4cd3-a89e-29bf32ca9814', 'odds', 'The claimants prevailed against odds that few observers had thought favorable.', '索赔人在几乎无人看好的情况下胜诉。'),
  ('ab6de38a-9813-4f9c-add8-04e55fb31572-ex1', 'ab6de38a-9813-4f9c-add8-04e55fb31572', 'gifted', 'She is a gifted musician.', '她是个有天赋的音乐家。'),
  ('ab6de38a-9813-4f9c-add8-04e55fb31572-ex2', 'ab6de38a-9813-4f9c-add8-04e55fb31572', 'gifted', 'The program identifies gifted students from chronically underserved districts.', '该项目从长期缺乏资源的地区发掘有天赋的学生。'),
  ('a77094ae-6b32-4d12-9e76-a2bbfe77598b-ex1', 'a77094ae-6b32-4d12-9e76-a2bbfe77598b', 'frustration', 'He sighed in frustration.', '他沮丧地叹了口气。'),
  ('a77094ae-6b32-4d12-9e76-a2bbfe77598b-ex2', 'a77094ae-6b32-4d12-9e76-a2bbfe77598b', 'frustration', 'Public frustration with the delays fueled demands for institutional reform.', '公众对拖延的不满激起了改革机构的呼声。'),
  ('f664fe5b-3db9-43ce-8a23-7bfa5743906c-ex1', 'f664fe5b-3db9-43ce-8a23-7bfa5743906c', 'medium', 'Cook the steak medium, please.', '请把牛排做成五分熟。'),
  ('f664fe5b-3db9-43ce-8a23-7bfa5743906c-ex2', 'f664fe5b-3db9-43ce-8a23-7bfa5743906c', 'medium', 'Social media has become the dominant medium for political mobilization.', '社交媒体已成为政治动员的主要媒介。'),
  ('c14e0f38-5c10-47ce-a664-3dca4a14980f-ex1', 'c14e0f38-5c10-47ce-a664-3dca4a14980f', 'physically', 'The job is physically demanding.', '这份工作对体力要求很高。'),
  ('c14e0f38-5c10-47ce-a664-3dca4a14980f-ex2', 'c14e0f38-5c10-47ce-a664-3dca4a14980f', 'physically', 'Verification proved physically impossible given the destruction of the records.', '由于记录已被销毁，核查实际上无法进行。'),
  ('1336b4ac-991c-4ce3-8a94-b2d9fc7613ca-ex1', '1336b4ac-991c-4ce3-8a94-b2d9fc7613ca', 'distinguish', 'Can you distinguish the twins?', '你能分辨出这对双胞胎吗？'),
