  ('f20d0eaf-2512-4c8d-9a8c-1c5dfb788e3c-ex1', 'f20d0eaf-2512-4c8d-9a8c-1c5dfb788e3c', 'impressive', 'The fireworks were impressive.', '烟花表演令人印象深刻。'),
