  ('2dc6edd1-6db1-4a94-8f86-79d10d631bd9-ex1', '2dc6edd1-6db1-4a94-8f86-79d10d631bd9', 'gaze', 'She fixed her gaze on the horizon.', '她凝视着地平线。'),
  ('2dc6edd1-6db1-4a94-8f86-79d10d631bd9-ex2', '2dc6edd1-6db1-4a94-8f86-79d10d631bd9', 'gaze', 'The regulatory gaze fell at last on practices long tolerated.', '监管的目光终于落在了长期被容忍的做法上。'),
