  ('9e5824c1-ff64-4ddd-83d3-ea7c34d6d438-ex1', '9e5824c1-ff64-4ddd-83d3-ea7c34d6d438', 'toe', 'I stubbed my toe on the chair.', '我的脚趾撞到了椅子。'),
